        for n in 3..=10u32 {
            entries.insert((n + 1, n), "Z/2".to_string());
        }
        entries.insert((2, 1), "0".to_string());
        entries.insert((3, 2), "Z".to_string());
        entries.insert((4, 3), "Z/2".to_string());
        entries.insert((5, 4), "Z/2".to_string());
        entries.insert((6, 5), "Z/2".to_string());
        entries.insert((3, 1), "0".to_string());
        entries.insert((4, 2), "Z/2".to_string());
        entries.insert((5, 2), "Z/2".to_string());
